name = "app_infocus"
description = "Applications in focus (/app/inFocus)"
output_columns = [
    "ENTRY CREATION", "DAY OF WEEK", "GMT OFFSET", "START", "END",
    "USAGE IN SECONDS", "ZSTREAMNAME", "ZVALUESTRING"
]
query = """
SELECT
    datetime(ZOBJECT.ZCREATIONDATE+978307200,'UNIXEPOCH','LOCALTIME') AS "ENTRY CREATION",
    CASE ZOBJECT.ZSTARTDAYOFWEEK
        WHEN '1' THEN 'Sunday'
        WHEN '2' THEN 'Monday'
        WHEN '3' THEN 'Tuesday'
        WHEN '4' THEN 'Wednesday'
        WHEN '5' THEN 'Thursday'
        WHEN '6' THEN 'Friday'
        WHEN '7' THEN 'Saturday'
    END AS "DAY OF WEEK",
    ZOBJECT.ZSECONDSFROMGMT/3600 AS "GMT OFFSET",
    datetime(ZOBJECT.ZSTARTDATE+978307200,'UNIXEPOCH','LOCALTIME') AS "START",
    datetime(ZOBJECT.ZENDDATE+978307200,'UNIXEPOCH','LOCALTIME') AS "END",
    (ZOBJECT.ZENDDATE-ZOBJECT.ZSTARTDATE) AS "USAGE IN SECONDS",
    ZOBJECT.ZSTREAMNAME,
    ZOBJECT.ZVALUESTRING
FROM ZOBJECT
WHERE ZSTREAMNAME IS '/app/inFocus'
ORDER BY "START"
"""
